const body = $input.first().json.body;

// Validate required fields
const required = ['call_id', 'caller_number', 'call_type', 'duration_seconds', 'transcript'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  throw new Error(`Missing fields: ${missing.join(', ')}`);
}

// Sanitise: strip any HTML from transcript
function stripHtml(str) {
  return String(str || '').replace(/<[^>]*>/g, '').trim();
}

// call_type: inbound_lead | appointment_set | support | other
// outcome: interested | not_interested | appointment_set | callback_requested | wrong_number

return [{
  json: {
    call_id: stripHtml(body.call_id),
    caller_number: stripHtml(body.caller_number),
    caller_name: stripHtml(body.caller_name || 'Unknown'),
    call_type: stripHtml(body.call_type),
    outcome: stripHtml(body.outcome || 'pending_review'),
    duration_seconds: parseInt(body.duration_seconds, 10),
    transcript: stripHtml(body.transcript),
    appointment_datetime: body.appointment_datetime || null,
    ai_summary: stripHtml(body.ai_summary || ''),
    recording_path: stripHtml(body.recording_path || ''),
    received_at: new Date().toISOString()
  }
}];

// Parse Ollama analysis
const raw = $input.first().json.response;
const match = raw.match(/\{[\s\S]*\}/);
if (!match) throw new Error('No JSON in Ollama response');

let analysis;
try {
  analysis = JSON.parse(match[0]);
} catch (e) {
  throw new Error(`JSON parse error: ${e.message}`);
}

const call = $node['Validate and Sanitise'].json;

return [{
  json: {
    ...call,
    lead_score: analysis.lead_score || 0,
    intent: analysis.intent || '',
    pain_points: analysis.pain_points || [],
    next_action: analysis.next_action || '',
    crm_note: analysis.crm_note || '',
    urgency: analysis.urgency || 'low',
    is_hot_lead: (analysis.lead_score || 0) >= 7
  }
}];

